    /// Program errors for mocks
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    #[repr(u32)]
    pub enum MocksError {
        /// This is an error.
        SomeError = 6000,
    }

    impl MocksError {
        /// Get the error code
        pub fn code(&self) -> u32 {
            *self as u32
        }

        /// Get the error message
        pub fn msg(&self) -> &'static str {
            match self {
                Self::SomeError => "This is an error.",
            }
        }

        /// Try to convert from error code
        pub fn from_code(code: u32) -> Option<Self> {
            match code {
                6000 => Some(Self::SomeError),

                _ => None,
            }
        }
    }

    impl std::fmt::Display for MocksError {
        fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
            write!(f, "{}: {}", self.code(), self.msg())
        }
    }

    impl std::error::Error for MocksError {}

